   373	/// Return `Some` if `intersecting` is non-empty after the operation, indicating overlapping hunks were found.
   374	pub fn take_intersecting(
   375	    iter: &mut Peekable<impl Iterator<Item = Hunk>>,
   376	    input: &mut Vec<Hunk>,
