use gix_merge::blob::builtin_driver::text;

fn generated() -> (Vec<u8>, Vec<u8>, Vec<u8>) {
    let mut base = String::new();
    for i in 0..28 { base.push_str(&format!("\tconst pre{i} = value;\n")); }
    base.push_str("\tconst uiState = inject(UI_STATE);\n");
    base.push_str("\tconst claudeCodeService = inject(CLAUDE_CODE_SERVICE);\n");
    base.push_str("\n");
    base.push_str("\t// ── MCP config modal ─────────────────────────────────────────────\n");
    base.push_str("\tlet mcpConfigModal = $state<CodegenMcpConfigModal>();\n");
    base.push_str("\tconst mcpClaudeConfigQuery = createQuery(() => ({ queryKey: ['mcp'] }));\n");
    for i in 0..35 { base.push_str(&format!("\tconst post{i} = value;\n")); }

    let mut ours = String::new();
    let insertion_point = base.find("\t// ── MCP config modal").unwrap();
    ours.push_str(&base[..insertion_point]);
    ours.push_str("\t// ── Actions ──────────────────────────────────────────────────────\n");
    for i in 0..70 {
        ours.push_str(&format!("\tasync function generatedAction{i}() {{\n\t\treturn {i};\n\t}}\n"));
    }
    ours.push_str(&base[insertion_point..]);

    let theirs = base.replace("\t// ── MCP config modal ─────────────────────────────────────────────\n", "");
    (base.into_bytes(), ours.into_bytes(), theirs.into_bytes())
}

fn main() {
    let (base, ours, theirs) = generated();
    let mut output = Vec::new();
    let mut input = imara_diff::intern::InternedInput::new(&[][..], &[][..]);
    let options = text::Options {
        diff_algorithm: imara_diff::Algorithm::Myers,
        conflict: text::Conflict::Keep {
            style: text::ConflictStyle::Merge,
            marker_size: std::num::NonZeroU8::new(7).unwrap(),
        },
    };
    let labels = text::Labels {
        ancestor: Some("base".into()),
        current: Some("ours".into()),
        other: Some("theirs".into()),
    };
    let resolution = text::function::merge(&mut output, &mut input, labels, &ours, &base, &theirs, options);
    println!("resolution={resolution:?} conflicts={}", output.windows(7).filter(|w| *w == b"<<<<<<<").count());
    if output.windows(7).any(|w| w == b"<<<<<<<") {
        println!("{}", String::from_utf8_lossy(&output));
    }
}
EOF
