use gix_merge::blob::{builtin_driver::text, Resolution};

fn merge_result(base: &[u8], ours: &[u8], theirs: &[u8], alg: imara_diff::Algorithm) -> (Resolution, usize, Vec<u8>) {
    let mut output = Vec::new();
    let mut input = imara_diff::InternedInput::new(&[][..], &[][..]);
    let options = text::Options {
        diff_algorithm: alg,
        conflict: text::Conflict::Keep {
            style: text::ConflictStyle::Merge,
            marker_size: std::num::NonZeroU8::new(7).unwrap(),
        },
    };
    let resolution = gix_merge::blob::builtin_driver::text(&mut output, &mut input, Default::default(), ours, base, theirs, options);
    let conflicts = output.windows(7).filter(|w| *w == b"<<<<<<<").count();
    (resolution, conflicts, output)
}

fn bytes(lines: &[usize], names: &[&str]) -> Vec<u8> {
    let mut out = Vec::new();
    for &l in lines {
        out.extend_from_slice(names[l].as_bytes());
        out.push(b'\n');
    }
    out
}

fn print_hunks(label: &str, algorithm: imara_diff::Algorithm, before: &[u8], after: &[u8]) {
    let input = imara_diff::InternedInput::new(imara_diff::sources::byte_lines(before), imara_diff::sources::byte_lines(after));
    let diff = imara_diff::Diff::compute(algorithm, &input);
    println!("{label} {algorithm:?}: {:?}", diff.hunks().collect::<Vec<_>>());
}

fn main() {
    let names = ["A", "B", "C", "D"];
    let insert = [4, 5, 6, 7];
    let insert_names = ["X", "Y", "Z", "W"];
    for len in 4..=9 {
        let total = 4usize.pow(len as u32);
        for mut n in 0..total {
            let mut base_lines = vec![0; len];
            for slot in &mut base_lines {
                *slot = n % 4;
                n /= 4;
            }
            for pos in 1..len-1 {
                let mut ours_lines = base_lines.clone();
                let ins = [insert[pos % 4], insert[(pos + 1) % 4], insert[(pos + 2) % 4]];
                ours_lines.splice(pos..pos, ins);
                let mut theirs_lines = base_lines.clone();
                theirs_lines.remove(pos);
                let all_names = ["A", "B", "C", "D", "X", "Y", "Z", "W"];
                let base = bytes(&base_lines, &all_names);
                let ours = bytes(&ours_lines, &all_names);
                let theirs = bytes(&theirs_lines, &all_names);
                let (mr, mc, mout) = merge_result(&base, &ours, &theirs, imara_diff::Algorithm::Myers);
                let (hr, hc, _) = merge_result(&base, &ours, &theirs, imara_diff::Algorithm::Histogram);
                if matches!(mr, Resolution::Conflict) && mc > 0 && matches!(hr, Resolution::Complete) && hc == 0 {
                    println!("FOUND len={len} pos={pos} base={base_lines:?}");
                    println!("base:\n{}ours:\n{}theirs:\n{}", String::from_utf8_lossy(&base), String::from_utf8_lossy(&ours), String::from_utf8_lossy(&theirs));
                    print_hunks("ours", imara_diff::Algorithm::Myers, &base, &ours);
                    print_hunks("theirs", imara_diff::Algorithm::Myers, &base, &theirs);
                    print_hunks("ours", imara_diff::Algorithm::Histogram, &base, &ours);
                    print_hunks("theirs", imara_diff::Algorithm::Histogram, &base, &theirs);
                    println!("myers output:\n{}", String::from_utf8_lossy(&mout));
                    return;
                }
            }
        }
    }
    println!("not found");
}
EOF
